import{_ as e,o as t,c as i,a as n}from"./app.357e38ad.js";var a="/aktivitaeten/BDM-2026-04/00_04-2026.jpg",r="/aktivitaeten/BDM-2026-04/01_04-2026.jpg",s="/aktivitaeten/BDM-2026-04/02_04-2026.jpg",d="/aktivitaeten/BDM-2026-04/03_04-2026.jpg",m="/aktivitaeten/BDM-2026-04/04_04-2026.jpg",g="/aktivitaeten/BDM-2026-04/05_04-2026.jpg",l="/aktivitaeten/BDM-2026-04/06_04-2026.jpg",o="/aktivitaeten/BDM-2026-04/07_04-2026.jpg",u="/aktivitaeten/BDM-2026-04/08_04-2026.jpg",p="/aktivitaeten/BDM-2026-04/09_04-2026.jpg",c="/aktivitaeten/BDM-2026-04/10_04-2026.jpg",h="/aktivitaeten/BDM-2026-04/11_04-2026.jpg",_="/aktivitaeten/BDM-2026-04/12_04-2026.jpg",M="/aktivitaeten/BDM-2026-04/13_04-2026.jpg",B="/aktivitaeten/BDM-2026-04/14_04-2026.jpg",k="/aktivitaeten/BDM-2026-04/15_04-2026.jpg",v="/aktivitaeten/BDM-2026-04/16_04-2026.jpg",D="/aktivitaeten/BDM-2026-04/17_04-2026.jpg",f="/aktivitaeten/BDM-2026-04/18_04-2026.jpg",b="/aktivitaeten/BDM-2026-04/19_04-2026.jpg",w="/aktivitaeten/BDM-2026-04/20_04-2026.jpg",A="/aktivitaeten/BDM-2026-04/21_04-2026.jpg",j="/aktivitaeten/BDM-2026-04/22_04-2026.jpg",S="/aktivitaeten/BDM-2026-04/23_04-2026.jpg",z="/aktivitaeten/BDM-2026-04/24_04-2026.jpg",F="/aktivitaeten/BDM-2026-04/25_04-2026.jpg",W="/aktivitaeten/BDM-2026-04/26_04-2026.jpg",E="/aktivitaeten/BDM-2026-04/27_04-2026.jpg",H="/aktivitaeten/BDM-2026-04/28_04-2026.jpg",L="/aktivitaeten/BDM-2026-04/29_04-2026.jpg",T="/aktivitaeten/BDM-2026-04/30_04-2026.jpg",C="/aktivitaeten/BDM-2026-04/31_04-2026.jpg",O="/aktivitaeten/BDM-2026-04/32_04-2026.jpg",P="/aktivitaeten/BDM-2026-04/33_04-2026.jpg",N="/aktivitaeten/BDM-2026-04/34_04-2026.jpg",K="/aktivitaeten/BDM-2026-04/35_04-2026.jpg",R="/aktivitaeten/BDM-2026-04/36_04-2026.jpg",G="/aktivitaeten/BDM-2026-04/37_04-2026.jpg",U="/aktivitaeten/BDM-2026-04/38_04-2026.jpg",x="/aktivitaeten/BDM-2026-04/39_04-2026.jpg",I="/aktivitaeten/BDM-2026-04/40_04-2026.jpg",V="/aktivitaeten/BDM-2026-04/41_04-2026.jpg",Q="/aktivitaeten/BDM-2026-04/42_04-2026.jpg",q="/aktivitaeten/BDM-2026-04/43_04-2026.jpg",Z="/aktivitaeten/BDM-2026-04/44_04-2026.jpg",J="/aktivitaeten/BDM-2026-04/45_04-2026.jpg",X="/aktivitaeten/BDM-2026-04/46_04-2026.jpg",y="/aktivitaeten/BDM-2026-04/47_04-2026.jpg",Y="/aktivitaeten/BDM-2026-04/48_04-2026.jpg",$="/aktivitaeten/BDM-2026-04/49_04-2026.jpg";const ee={},te=n('<h1 id="bilder-des-monats-april-2026" tabindex="-1"><a class="header-anchor" href="#bilder-des-monats-april-2026" aria-hidden="true">#</a> Bilder des Monats April 2026</h1><p><img src="'+a+'" alt="Bilder des Monats"><img src="'+r+'" alt="Bilder des Monats"><img src="'+s+'" alt="Bilder des Monats"><img src="'+d+'" alt="Bilder des Monats"><img src="'+m+'" alt="Bilder des Monats"><img src="'+g+'" alt="Bilder des Monats"></p><p>Nachdem die neue Sommerzeit die Helligkeit nach dem QRL ein wenig verl\xE4ngert hatte und gleichzeitig wolkenloser Himmel mit 16\xB0C den Wetterbericht zierte, hatte DB4SCW am 02.04.2026 den 2fer aus DE-0028 und DE-1211 aktiviert. Sch\xF6n am Trail in der Aktivierungszone gelegen bot sich der Pfaffenbrunnen optimal an. Ausr\xFCstung war die PAC-12 Vertikal (perfektes SWR beim ersten Aufbauen), sowie der 857D aus dem Portabelrucksack.</p><p>40m am Anfang war z\xE4h, 20m noch z\xE4her, der R\xFCckwechsel auf 40m brachte dann den gew\xFCnschten Erfolg und kleinere Phasen von &quot;Pileup-light&quot;.</p><p>Abbau und R\xFCckweg erfolgten dann mit wundersch\xF6nem Sonnenuntergang nach erfolgreicher Aktivierung (18x 40m, 5x 20m, davon 4x P2P).</p><p>Sch\xF6ner Abschluss eines Arbeitstages. Gerne wieder, lieber Wettergott.</p><p><img src="'+l+'" alt="Bilder des Monats"><img src="'+o+'" alt="Bilder des Monats"><img src="'+u+'" alt="Bilder des Monats"><img src="'+p+'" alt="Bilder des Monats"><img src="'+c+'" alt="Bilder des Monats"><img src="'+h+'" alt="Bilder des Monats"></p><p>DL2MBN Mixed Activation SSB / CW</p><p>Ich hatte noch eine alten Kinder Fahrrad Anh\xE4nger unter dem Wohnwagen liegen, also dachte ich mir das ich den ein bisschen umbaue damit ich mein Funk Equipment zum nahegelegenen Park DE-1059 bringe. Gesagt getan alles eingepackt Und mit meiner Tochter zum Spot gelaufen. Nach dem Aufbau ( 7 m Mast EFHW und FT891 ) ging es auch gleich los aber erst mal in SSB. Mein Highlight war W1OW und K2UPD in SSB um 10:00 UTC . Danach ging es weiter mit CW auch dort gab es tolle Kontakte mit meinen Drau\xDFenfunker Kollegen. So kamen in 1 H 25 Min 43 entspannte QSO s zu Stande. Somit endet f\xFCr uns morgen der Urlaub auf unserem Campingplatz ( Dauercamper ) mit einer tollen Aktivierung.</p><p>73 DL2MBN e e</p><p><img src="'+_+'" alt="Bilder des Monats"><img src="'+M+'" alt="Bilder des Monats"><img src="'+B+'" alt="Bilder des Monats"><img src="'+k+'" alt="Bilder des Monats"><img src="'+v+'" alt="Bilder des Monats"><img src="'+D+'" alt="Bilder des Monats"><img src="'+f+'" alt="Bilder des Monats"></p><p>DL2MBN Mixed Activation CW &amp; SSB</p><p>Heute auf dem Weg nach Augsburg mit dem Ziel Ikea war die Aktivierung f\xFCr den Park DE-1057 eingeplant. Das Wetter war perfekt und die Bedingungen waren auch gut. Mit dabei waren das FT891 + EFHW und 100 Ah Akku Box. In einer Stunde kamen 38 Verbindungen zustande, darunter auch viele DF zu DF Kontakte.</p><p>73 DL2MBN</p><p><img src="'+b+'" alt="Bilder des Monats"><img src="'+w+'" alt="Bilder des Monats"><img src="'+A+'" alt="Bilder des Monats"><img src="'+j+'" alt="Bilder des Monats"><img src="'+S+'" alt="Bilder des Monats"></p><p>Statt Funken im Regen heute mal wieder Funken am Regen. DF9HC auf Dienstreise und nach der Arbeit ist DE-0015 gleich vor der T\xFCr. Mit 20 W und der Teleskopantenne kam heute sogar Japan auf CW ins Log.</p><p><img src="'+z+'" alt="Bilder des Monats"><img src="'+F+'" alt="Bilder des Monats"><img src="'+W+'" alt="Bilder des Monats"><img src="'+E+'" alt="Bilder des Monats"></p><p>Von Markus, DG6KP: Beim meinen Outdoor-Funkaktivit\xE4ten habe ich in der Umgebung meines Wohnortes in Euskirchen mehrere Stellen gefunden, an die ich immer wieder gerne zur\xFCckkehre. Es handelt sich meist um 2fer, da ich privilegiert mitten im Naturpark Rheinland DE-0048 wohne. Eine dieser Stellen liegt auf dem Gipfel des Lauertzbergs (JO30IO), 307m hoch und f\xFCr mich auch mit dem Fahrrad erreichbar \u2013 hin leider immer nur bergauf\u2026 \xDCber den Gipfel des Lauertzbergs geht der Fernwanderweg E8 (DE-0626) und der Gipfel liegt (nat\xFCrlich) im Naturpark Rheinland (DE-0048). Ich habe mehrfach von dort gefunkt und immer gedacht, dass m\xFCsste doch auch auf UKW gehen. Leider blieben Anrufe auf der 2m Anruffrequenz bisher unbeantwortet und Relais z\xE4hlen nicht. Also habe ich in den Contest-Kalender geschaut und den DARC UKW-Fr\xFChlingscontest am 04.04.2026 gefunden. Das sollte doch funktionieren! In der Garage meine 9ele Yagi f\xFCr 2m herausgekramt, die stammt noch aus meiner Anfangszeit als C-Lizenzler in den 80ern. Mit dem FT-857 kamen so 23 QSO ins Log (mit etwas Unterst\xFCtzung aus meinem OV G11), die ODX lag bei 360 km. Erwartungsgem\xE4\xDF fast alle in n\xF6rdlicher bzw. \xF6stlicher Richtung, im S\xFCden und Westen sind die Eifel bzw. die Ardennen im Weg. Um dar\xFCber hinwegzukommen ist der Lauertzberg nicht hoch genug. Die 23 QSO reichten f\xFCr Platz 23 im Wettbewerb, eine reine 2m Aktivierung und dem N1CC bin ich auch ein kleines St\xFCck n\xE4her.</p><p><img src="'+H+'" alt="Bilder des Monats"><img src="'+L+'" alt="Bilder des Monats"><img src="'+T+'" alt="Bilder des Monats"><img src="'+C+'" alt="Bilder des Monats"></p><p>War heute mal auf f\xFCr mich eher ungew\xF6hnlichen Aktivierungen. Da ich zu Hause keine Berge habe, ist SOTA immer was besonderes f\xFCr mich. Heute ging&#39;s mit dem l\xE4ngsten Sessellift des Bayrischen Waldes auf den Hohenbogen, dann noch ein paar H\xF6henmeter zu Fu\xDF zum Schwarzriegel (DM/BM-0368). Trotz nicht so toller Bedingungen war die Aktivierung schnell gegl\xFCckt, gef\xFChlt sind hier noch mehr Hunter unterwegs als bei POTA. Sp\xE4ter ging es noch zu Fu\xDF in die Tschechische Republik und als OK/DF9HC gelang mir die Aktivierung von CZ-0009 - meinem ersten Park in dem Land. 73 de DF9HC</p><p><img src="'+O+'" alt="Bilder des Monats"><img src="'+P+'" alt="Bilder des Monats"><img src="'+N+'" alt="Bilder des Monats"><img src="'+K+'" alt="Bilder des Monats"><img src="'+R+'" alt="Bilder des Monats"><img src="'+G+'" alt="Bilder des Monats"><img src="'+U+'" alt="Bilder des Monats"></p><p>DL2MBN Mixed Operation CW / SSB DE-0791</p><p>Heute war das Wetter perfekt f\xFCr einen etwas l\xE4ngeren Spaziergang um zum Spot zu kommen. Ausgesucht haben wir uns den Lech Erlebnis Weg der am Forggensee vorbei geht. Die MUF lag bei ca. 22.5 MHz . Mit dabei hatte ich die EFHW meinen 7 m Mast das QMX und das FT891 das ich f\xFCr SSB genutzt habe. Zusammen gekommen sind am Ende auf 20m und 40m 23 qsos in ca 1 Stunde. 19 CW und 3 SSB qsos. Mit dabei waren auch wieder ein paar DF2DF Kontakte. Danke an alle Hunter es war ein wundersch\xF6ner Tag.</p><p>73 DL2MBN</p><p><img src="'+x+'" alt="Bilder des Monats"><img src="'+I+'" alt="Bilder des Monats"><img src="'+V+'" alt="Bilder des Monats"><img src="'+Q+'" alt="Bilder des Monats"><img src="'+q+'" alt="Bilder des Monats"><img src="'+Z+'" alt="Bilder des Monats"><img src="'+J+'" alt="Bilder des Monats"><img src="'+X+'" alt="Bilder des Monats"></p><p>DB6NL in DE-0959 - Langsam wird es w\xE4rmer und ich konnte mal wieder auf den Hausberg. Knapp 200m \xFCber NN. Die ersten 20 QSOs hab ich \xFCber die KW ins Log geholt. Nach 13:00 Uhr utc begann der 2m-Ausbildungscontest und es kamen nochmal 18 QSOs auf 2m in FM ins Log. Beim Ausbildungscontest waren auch einige Anf\xE4nger und mehrere POTA-Stationen on air\u2026</p><p><img src="'+y+'" alt="Bilder des Monats"><img src="'+Y+'" alt="Bilder des Monats"></p><p>Am 25.04.2026 haben sich im Landschaftspark Hachinger Tal (POTA-Referenz DE-0546) die OMs DO2BEN, DL1MIE, DH1MFS und DB7GKA getroffen, um das Drau\xDFenfunker-Fr\xFChlingsfest mit einer gemeinsamen POTA-Aktivierung zu zelebrieren. Bei herrlichstem Fr\xFChlingswetter wurden gemeinsam die Eigenbauantennen aufgebaut, gegenseitig begutachtet, \xFCber die Vor- und Nachteile gefachsimpelt und nette Gespr\xE4che gef\xFChrt.</p><p>Insgesamt waren im weitl\xE4ufigen Park f\xFCnf Antennen im Einsatz. Eine EFHW mit circa 20 Meter Draht f\xFCr die B\xE4nder 10, 15, 20 und 40 Meter aufgebaut als Inverted-V an einem 7-Meter-GFK-Mast. Eine T2LT f\xFCr 15 Meter die ebenfalls mit einem 7-Meter-Mast auf H\xF6he gebracht wurde. Die dritte Antenne im Bunde war ein Dipol abgespannt als Inverted-V, dessen Speisepunkt sich in circa 5 Meter H\xF6he befunden hat. Der Dipol konnte durch Auf- oder Abwickeln des Drahtes von der kleinen Drahthaspel mittels der Markierungen am Draht sehr einfach auf eine resonante L\xE4nge f\xFCr 20 und 40 Meter gebracht und mitsamt der Drahthaspel abgespannt werden. Als vierte Antenne diente eine endgespeiste Drahtantenne in spiralf\xF6rmiger Wicklung um einen 12-Meter-GFK-Mast mit einem 1:9-UnUn und zwei Meter Gegengewichtsdraht geerdet an einem Metallabfalleimer der gleichzeitig als Masthalter diente. Zu gute Letzt war auch noch die ber\xFChmte Draussenfunker-Vertikal aufgebaut. Der Funkbetrieb wurde mit den gut abgehangenen Arbeitspferden FT-891 und IC-705 in SSB, CW, FT8 und VARA durchgef\xFChrt.</p><p>Der kleine Antennenwald hat immer wieder interessierte Passanten angelockt, die uns mit Fragen zu unserem Happening auf Trab hielten. Alles in allem war es ein sehr sch\xF6nes Treffen!</p><p><img src="'+$+'" alt="Bilder des Monats"></p>',31),ie=[te];function ne(ae,re){return t(),i("div",null,ie)}var de=e(ee,[["render",ne],["__file","2026-04-30-Bilder-Des-Monats-April.html.vue"]]);export{de as default};
